import{_ as t,o as r,c as e,a0 as c}from"./chunks/framework.CEvT70OL.js";const u=JSON.parse('{"title":"TypeScracherとは何？","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"01_introduction/02.md","filePath":"01_introduction/02.md"}'),i={name:"01_introduction/02.md"};function l(o,a,h,s,n,d){return r(),e("div",null,[...a[0]||(a[0]=[c('<h1 id="typescracherとは何" tabindex="-1">TypeScracherとは何？ <a class="header-anchor" href="#typescracherとは何" aria-label="Permalink to &quot;TypeScracherとは何？&quot;">​</a></h1><h2 id="特徴" tabindex="-1">特徴 <a class="header-anchor" href="#特徴" aria-label="Permalink to &quot;特徴&quot;">​</a></h2><p>Scratch3風 ～ Scratch3でやれることを「同様に」で表現できることを目指しています。</p><h3 id="イベント起動型" tabindex="-1">イベント起動型 <a class="header-anchor" href="#イベント起動型" aria-label="Permalink to &quot;イベント起動型&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">イベント起動</p><p>Scratch3のハットブロックに対応したスレッド定義(非同期/並列動作)</p></div><h3 id="体系的なメソッド構成" tabindex="-1">体系的なメソッド構成 <a class="header-anchor" href="#体系的なメソッド構成" aria-label="Permalink to &quot;体系的なメソッド構成&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">直観的に使える体系的なメソッド構成</p><p>Scratch3のブロックグループに対応したメソッドグループを用意しています。<br></p><ul><li>Motion(動き)</li><li>Looks(見た目)</li><li>Sound(音)</li><li>Events(イベント)</li><li>Control(制御)</li><li>Sensing(調べる)</li><li>Pen(ペン)</li><li>Operations(演算)</li><li>Variables(変数)</li></ul></div><h3 id="scratch3座標系" tabindex="-1">Scratch3座標系 <a class="header-anchor" href="#scratch3座標系" aria-label="Permalink to &quot;Scratch3座標系&quot;">​</a></h3><p>ステージの大きさは、横 480ピクセル、縦 360ピクセル、とScratch3と同じにしています。</p><p>座標(X,Y)は ステージの中央が(X,Y)=(0,0)であり、座標の扱いはScratch3と完全に同じです。</p><h3 id="scratch3と同等の衝突判定と色判定" tabindex="-1">Scratch3と同等の衝突判定と色判定 <a class="header-anchor" href="#scratch3と同等の衝突判定と色判定" aria-label="Permalink to &quot;Scratch3と同等の衝突判定と色判定&quot;">​</a></h3><p>衝突判定、色判定は、Scratch3と同じく、見えたままの判定を提供します。</p><h3 id="画像ファイル" tabindex="-1">画像ファイル <a class="header-anchor" href="#画像ファイル" aria-label="Permalink to &quot;画像ファイル&quot;">​</a></h3><p>SVG画像、BITMAP画像、どちらも使用可能です。<br></p><p>Scratch3から出力した画像はそのまま使用することができます。<br></p><h3 id="音ファイル" tabindex="-1">音ファイル <a class="header-anchor" href="#音ファイル" aria-label="Permalink to &quot;音ファイル&quot;">​</a></h3><p>Scratch3で使える音ファイルは、すべてTypsScratcherでも利用可能です。</p><h3 id="繰り返しループはフレームに連動" tabindex="-1">繰り返しループはフレームに連動 <a class="header-anchor" href="#繰り返しループはフレームに連動" aria-label="Permalink to &quot;繰り返しループはフレームに連動&quot;">​</a></h3><p>フレームごとに繰り返しループを１回分処理します。これは　Scratch3と同じです。</p><h3 id="プログラミングが楽" tabindex="-1">プログラミングが楽 <a class="header-anchor" href="#プログラミングが楽" aria-label="Permalink to &quot;プログラミングが楽&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">楽々プログラミング</p><ul><li>危ないコードを排除 ～ 危ないコードを教えてくれて、適切なコードに補正可能です(ESLINTを利用)。</li><li>コーディングが楽 ～ Typescriptのコード補完により、候補メソッドを教えてくれます。</li><li>体系的なメソッド構成 ～ 提供するメソッドはScratch3のブロック群を参考にして構成されています。</li></ul></div><h3 id="機能拡張への道" tabindex="-1">機能拡張への道 <a class="header-anchor" href="#機能拡張への道" aria-label="Permalink to &quot;機能拡張への道&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">機能拡張</p><p>『TypeScratcher』が提供するクラスを継承し、機能拡張された「スプライトクラス」を作り出すことも可能です。 typescriptを使いこなして、独自の機能拡張にも挑戦しましょう。</p></div><hr>',24)])])}const b=t(i,[["render",l]]);export{u as __pageData,b as default};
